INSERT IGNORE INTO `#__j2commerce_emailtemplates` (`j2commerce_emailtemplate_id`, `email_type`, `receiver_type`, `orderstatus_id`, `group_id`, `paymentmethod`, `subject`, `body`, `body_json`, `body_source`, `body_source_file`, `custom_css`, `language`, `enabled`, `ordering`) VALUES (1,'transactional','*','1','*','*','Thanks for your order, [BILLING_FIRSTNAME]! - #[ORDERID]','<!-- J2Commerce Order Confirmed - Modern Template -->\r\n<table style=\"background-color: [email_bg_color]; font-family: Arial, Helvetica, sans-serif;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 30px 10px;\" align=\"center\">\r\n<table class=\"email-container\" style=\"max-width: 600px; width: 100%; background-color: #fff;\" border=\"0\" width=\"600\" cellspacing=\"0\" cellpadding=\"0\"><!-- Logo Bar -->\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 20px 30px; background-color: #ffffff; border-radius: 12px 12px 0 0; text-align: center;\">[IF:STORE_LOGO_URL] <a href=\"[SITEURL]\" target=\"_blank\" rel=\"noopener\"> <img style=\"display: block; border: 0; height: [LOGO_MAX_HEIGHT]px; width: auto;\" src=\"[STORE_LOGO_URL]\" alt=\"[SITENAME]\"> </a> [/IF:STORE_LOGO_URL] [IFNOT:STORE_LOGO_URL] <a style=\"font-size: 22px; font-weight: bold; color: [accent_color]; text-decoration: none;\" href=\"[SITEURL]\" target=\"_blank\" rel=\"noopener\">[SITENAME]</a> [/IFNOT:STORE_LOGO_URL]</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0; border: 0; font-size: 0; line-height: 0; height: 0; overflow: hidden;\">[HOOK:AFTER_HEADER]</td>\r\n</tr>\r\n<!-- Success Banner -->\r\n<tr>\r\n<td style=\"background-color: #059669; padding: 32px 30px; text-align: center;\"><!-- Checkmark Circle -->\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\" align=\"center\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 56px; height: 56px; background-color: rgba(255,255,255,0.2); border-radius: 50%; text-align: center; vertical-align: middle; font-size: 28px; color: #ffffff;\">✓</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h1 style=\"margin: 16px 0 6px 0; font-size: 26px; font-weight: bold; color: #ffffff;\">Order Confirmed</h1>\r\n<p style=\"margin: 0; font-size: 15px; color: #d1fae5;\">Thank you, [CUSTOMER_NAME]! Your order #[ORDERID] has been confirmed.</p>\r\n</td>\r\n</tr>\r\n<!-- Status Tracker -->\r\n<tr>\r\n<td style=\"background-color: #ffffff; padding: 24px 20px;\">\r\n<table border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr><!-- Step 1: Ordered (Active) -->\r\n<td class=\"tracker-step\" style=\"width: 33%; text-align: center; padding: 0 8px;\">\r\n<table border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td align=\"center\">\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 32px; height: 32px; background-color: #059669; border-radius: 50%; text-align: center; vertical-align: middle; color: #ffffff; font-size: 14px; font-weight: bold;\">✓</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding-top: 6px; font-size: 11px; font-weight: bold; color: #059669; text-align: center;\">Ordered</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n<!-- Step 2: Processing (Pending) -->\r\n<td class=\"tracker-step\" style=\"width: 33%; text-align: center; padding: 0 8px;\">\r\n<table border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td align=\"center\">\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 32px; height: 32px; background-color: #e5e7eb; border-radius: 50%; text-align: center; vertical-align: middle; color: #9ca3af; font-size: 14px; font-weight: bold;\">2</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding-top: 6px; font-size: 11px; color: #9ca3af; text-align: center;\">Processing</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n<!-- Step 3: Shipped (Pending) -->\r\n<td class=\"tracker-step\" style=\"width: 34%; text-align: center; padding: 0 8px;\">\r\n<table border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td align=\"center\">\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 32px; height: 32px; background-color: #e5e7eb; border-radius: 50%; text-align: center; vertical-align: middle; color: #9ca3af; font-size: 14px; font-weight: bold;\">3</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding-top: 6px; font-size: 11px; color: #9ca3af; text-align: center;\">Shipped</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<!-- Progress Bar -->\r\n<tr>\r\n<td style=\"padding: 12px 8px 0 8px;\" colspan=\"3\">\r\n<table style=\"background-color: #e5e7eb; border-radius: 4px; height: 4px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 33%; background-color: #059669; border-radius: 4px; height: 4px;\"> </td>\r\n<td style=\"width: 67%; height: 4px;\"> </td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<!-- Order Details Summary -->\r\n<tr>\r\n<td style=\"padding: 0 20px;\">\r\n<table style=\"background-color: #f0fdf4; border-radius: 8px; margin-bottom: 4px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 14px 20px; font-size: 13px; color: #374151;\"><strong>Order #[ORDERID]</strong>  •  [ORDERDATE] [IF:INVOICENO]  •  Invoice: [INVOICENO][/IF:INVOICENO]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0; border: 0; font-size: 0; line-height: 0; height: 0; overflow: hidden;\">[HOOK:BEFORE_ITEMS]</td>\r\n</tr>\r\n<!-- Order Items Card -->\r\n<tr>\r\n<td class=\"mobile-padding\" style=\"padding: 16px 20px;\">[ITEMS_LOOP] [/ITEMS_LOOP]\r\n<table style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\"><!-- Card Header -->\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 16px 20px; border-bottom: 1px solid #f3f4f6;\" colspan=\"4\"><span style=\"font-size: 15px; font-weight: bold; color: [text_color];\">Items Ordered</span></td>\r\n</tr>\r\n<!-- Column Headers -->\r\n<tr>\r\n<td style=\"padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;\" colspan=\"2\">Product</td>\r\n<td style=\"padding: 10px 10px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: center; width: 45px;\">Qty</td>\r\n<td style=\"padding: 10px 20px; font-size: 11px; font-weight: bold; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; text-align: right; width: 90px;\">Total</td>\r\n</tr>\r\n<!-- Items -->\r\n<tr>\r\n<td style=\"padding: 12px 0 12px 20px; border-top: 1px solid #f3f4f6; vertical-align: top; width: 60px;\">[IF:ITEM_IMAGE] <img style=\"border-radius: 6px; object-fit: cover; display: block; border: 1px solid #f3f4f6;\" src=\"[ITEM_IMAGE]\" alt=\"[ITEM_NAME]\" width=\"50\" height=\"50\"> [/IF:ITEM_IMAGE]</td>\r\n<td style=\"padding: 12px 10px; border-top: 1px solid #f3f4f6; vertical-align: top;\"><span style=\"font-size: 14px; font-weight: 600; color: [text_color];\">[ITEM_NAME]</span> [IF:ITEM_SKU]<br><span style=\"font-size: 12px; color: #9ca3af;\">SKU: [ITEM_SKU]</span>[/IF:ITEM_SKU] [IF:ITEM_OPTIONS]<br><span style=\"font-size: 12px; color: #6b7280;\">[ITEM_OPTIONS]</span>[/IF:ITEM_OPTIONS] <br><span style=\"font-size: 12px; color: #6b7280;\">[ITEM_PRICE] each</span></td>\r\n<td style=\"padding: 12px 10px; border-top: 1px solid #f3f4f6; text-align: center; vertical-align: top; font-size: 14px; color: [text_color];\">[ITEM_QTY]</td>\r\n<td style=\"padding: 12px 20px; border-top: 1px solid #f3f4f6; text-align: right; vertical-align: top; font-size: 14px; font-weight: 600; color: [text_color];\">[ITEM_TOTAL]</td>\r\n</tr>\r\n<!-- Totals -->\r\n<tr>\r\n<td style=\"padding: 0;\" colspan=\"4\">\r\n<table style=\"background-color: #f9fafb; border-top: 1px solid #e5e7eb;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 10px 20px 2px 20px; font-size: 13px; color: #6b7280;\">Subtotal</td>\r\n<td style=\"padding: 10px 20px 2px 20px; font-size: 13px; color: #6b7280; text-align: right;\">[SUBTOTAL]</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 6px 20px; font-size: 13px; color: #059669;\">[IF:DISCOUNT_AMOUNT]Discount [IF:COUPON_CODE]([COUPON_CODE])[/IF:COUPON_CODE][/IF:DISCOUNT_AMOUNT]</td>\r\n<td style=\"padding: 6px 20px; font-size: 13px; color: #059669; text-align: right;\">[IF:DISCOUNT_AMOUNT]-[DISCOUNT_AMOUNT][/IF:DISCOUNT_AMOUNT]</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0;\" colspan=\"2\">[TAX_LINES]</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 6px 20px; font-size: 13px; color: #6b7280;\">[IF:SHIPPING_AMOUNT]Shipping [IF:SHIPPING_METHOD]([SHIPPING_METHOD])[/IF:SHIPPING_METHOD][/IF:SHIPPING_AMOUNT]</td>\r\n<td style=\"padding: 6px 20px; font-size: 13px; color: #6b7280; text-align: right;\">[IF:SHIPPING_AMOUNT][SHIPPING_AMOUNT][/IF:SHIPPING_AMOUNT]</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 14px 20px; font-size: 16px; font-weight: bold; color: [text_color]; border-top: 2px solid #e5e7eb;\">Total</td>\r\n<td style=\"padding: 14px 20px; font-size: 16px; font-weight: bold; color: [text_color]; text-align: right; border-top: 2px solid #e5e7eb;\">[ORDERAMOUNT]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0; border: 0; font-size: 0; line-height: 0; height: 0; overflow: hidden;\">[HOOK:AFTER_ITEMS]</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0; border: 0; font-size: 0; line-height: 0; height: 0; overflow: hidden;\">[HOOK:BEFORE_SHIPPING]</td>\r\n</tr>\r\n<!-- Shipping & Billing Cards -->\r\n<tr>\r\n<td class=\"mobile-padding\" style=\"padding: 0 20px 16px 20px;\">\r\n<table border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr><!-- Billing -->\r\n<td class=\"address-col\" style=\"width: 50%; vertical-align: top; padding-right: 8px;\">\r\n<table style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;\">Billing Address</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 14px 18px; font-size: 14px; color: [text_color]; line-height: 1.6;\"><strong>[BILLING_FIRSTNAME] [BILLING_LASTNAME]</strong>[IF:BILLING_COMPANY]<br>[BILLING_COMPANY][/IF:BILLING_COMPANY]<br>[BILLING_ADDRESS_1][IF:BILLING_ADDRESS_2]<br>[BILLING_ADDRESS_2][/IF:BILLING_ADDRESS_2]<br>[BILLING_CITY], [BILLING_STATE] [BILLING_ZIP]<br>[BILLING_COUNTRY][IF:BILLING_PHONE]<br>[BILLING_PHONE][/IF:BILLING_PHONE]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n<!-- Shipping -->\r\n<td class=\"address-col\" style=\"width: 50%; vertical-align: top; padding-left: 8px;\">[IF:SHIPPING_FIRSTNAME]\r\n<table style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;\">Shipping Address</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 14px 18px; font-size: 14px; color: [text_color]; line-height: 1.6;\"><strong>[SHIPPING_FIRSTNAME] [SHIPPING_LASTNAME]</strong><br>[SHIPPING_ADDRESS_1][IF:SHIPPING_ADDRESS_2]<br>[SHIPPING_ADDRESS_2][/IF:SHIPPING_ADDRESS_2]<br>[SHIPPING_CITY], [SHIPPING_STATE] [SHIPPING_ZIP]<br>[SHIPPING_COUNTRY]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n[/IF:SHIPPING_FIRSTNAME]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<!-- Payment Info Card -->\r\n<tr>\r\n<td class=\"mobile-padding\" style=\"padding: 0 20px 16px 20px;\">\r\n<table style=\"background-color: #ffffff; border: 1px solid #e5e7eb; border-radius: 10px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 14px 18px; border-bottom: 1px solid #f3f4f6; font-size: 13px; font-weight: bold; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px;\">Payment Information</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 14px 18px; font-size: 14px; color: [text_color];\"><strong>Method:</strong> [PAYMENT_TYPE] [IF:SHIPPING_TRACKING_ID]<br><strong>Tracking ID:</strong> [SHIPPING_TRACKING_ID][/IF:SHIPPING_TRACKING_ID]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0; border: 0; font-size: 0; line-height: 0; height: 0; overflow: hidden;\">[HOOK:AFTER_PAYMENT]</td>\r\n</tr>\r\n<!-- Customer Note -->\r\n<tr>\r\n<td class=\"mobile-padding\" style=\"padding: 0;\">[IF:CUSTOMER_NOTE]\r\n<table style=\"margin: 0; padding: 0;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 0 20px 16px 20px;\">\r\n<table style=\"background-color: #fffbeb; border: 1px solid #fde68a; border-radius: 10px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 14px 18px; font-size: 13px; font-weight: bold; color: #92400e;\">Your Note</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0 18px 14px 18px; font-size: 14px; color: #78350f; line-height: 1.5;\">[CUSTOMER_NOTE]</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n[/IF:CUSTOMER_NOTE]</td>\r\n</tr>\r\n<!-- View Order Button -->\r\n<tr>\r\n<td style=\"padding: 10px 20px 24px 20px; text-align: center;\">\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\" align=\"center\">\r\n<tbody>\r\n<tr>\r\n<td style=\"background-color: [accent_color]; border-radius: 8px; text-align: center;\"><a style=\"display: inline-block; padding: 14px 36px; color: #ffffff; text-decoration: none; font-size: 15px; font-weight: bold; letter-spacing: 0.3px;\" href=\"[INVOICE_URL]\">View Your Order</a></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<!-- Support Block -->\r\n<tr>\r\n<td class=\"mobile-padding\" style=\"padding: 0 20px 20px 20px;\">\r\n<table style=\"background-color: #f9fafb; border-radius: 10px;\" border=\"0\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 18px 20px; text-align: center; font-size: 13px; color: #6b7280; line-height: 1.6;\"><strong style=\"color: [text_color];\">Need help?</strong><br>If you have any questions about your order, reply to this email or contact us at <a style=\"color: [accent_color]; text-decoration: none;\" href=\"mailto:[BILLING_EMAIL]\">[SITENAME]</a>.</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"padding: 0; border: 0; font-size: 0; line-height: 0; height: 0; overflow: hidden;\">[HOOK:BEFORE_FOOTER]</td>\r\n</tr>\r\n<!-- Footer -->\r\n<tr>\r\n<td style=\"padding: 24px 40px; background-color: #ffffff; border-radius: 0 0 12px 12px; border-top: 1px solid #f3f4f6; text-align: center;\"><!-- Social Links -->\r\n<table style=\"margin-bottom: 14px;\" border=\"0\" cellspacing=\"0\" cellpadding=\"0\" align=\"center\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding: 0 8px;\">[IF:SOCIAL_FACEBOOK]<a style=\"display: inline-block; width: 32px; height: 32px; background-color: #e5e7eb; border-radius: 50%; text-align: center; line-height: 32px; text-decoration: none; font-size: 14px; color: #6b7280;\" href=\"[SOCIAL_FACEBOOK]\">f</a>[/IF:SOCIAL_FACEBOOK]</td>\r\n<td style=\"padding: 0 8px;\">[IF:SOCIAL_TWITTER]<a style=\"display: inline-block; width: 32px; height: 32px; background-colo